import ai from "@/lib/server/google-ai";
import { ApiResponse } from "@/lib/server/response";
import { EditorForm, Form } from "@/types/form";
import { Type } from "@google/genai";
import { NextRequest, NextResponse } from "next/server";
import { extractText } from "unpdf";

export async function POST(request: NextRequest) {
  try {
    // 1. Ambil data Form dari request
    const formData = await request.formData();
    const file = formData.get("file_pdf") as File;

    // Validasi apakah file di-upload
    if (!file) {
      return NextResponse.json(
        { error: "Mohon upload file PDF terlebih dahulu." },
        { status: 400 },
      );
    }

    // 2. Ubah file PDF langsung menjadi ArrayBuffer (di dalam memori RAM)
    const arrayBuffer = await file.arrayBuffer();
    const uint8Array = new Uint8Array(arrayBuffer);

    // 3. Ekstrak teks menggunakan unpdf
    const { text, totalPages } = await extractText(uint8Array, {
      mergePages: true,
    });

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            description: { type: Type.STRING },
            questions: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  title: { type: Type.STRING },
                  type: {
                    type: Type.STRING,
                    enum: ["text", "radio", "checkbox", "select"],
                  },
                  totalScore: { type: Type.NUMBER },
                  correctAnswers: {
                    type: Type.ARRAY,
                    items: { type: Type.STRING },
                  },
                  options: {
                    type: Type.ARRAY,
                    items: {
                      type: Type.OBJECT,
                      properties: {
                        id: { type: Type.STRING },
                        title: { type: Type.STRING },
                      },
                      required: ["id", "title"],
                    },
                  },
                  required: { type: Type.BOOLEAN },
                },
                required: [
                  "id",
                  "title",
                  "type",
                  "totalScore",
                  "correctAnswers",
                  "options",
                  "required",
                ],
              },
            },
            settings: {
              type: Type.OBJECT,
              properties: {
                isQuiz: { type: Type.BOOLEAN },
                allowSeeWrongAnswers: { type: Type.BOOLEAN },
                allowSeeCorrectAnswers: { type: Type.BOOLEAN },
                allowSeeScore: { type: Type.BOOLEAN },
                defaultScoreValue: { type: Type.NUMBER },
                shuffleQuestions: { type: Type.BOOLEAN },
                allowSeeResult: { type: Type.BOOLEAN },
                questionRequiredDefault: { type: Type.BOOLEAN },
              },
              required: [
                "isQuiz",
                "allowSeeWrongAnswers",
                "allowSeeCorrectAnswers",
                "allowSeeScore",
                "defaultScoreValue",
                "shuffleQuestions",
                "allowSeeResult",
                "questionRequiredDefault",
              ],
            },
            totalScore: { type: Type.NUMBER },
          },
          required: [
            "title",
            "description",
            "questions",
            "settings",
            "totalScore",
          ],
        },
      },
      contents: [
        {
          role: "user",
          parts: [
            {
              text: `Kamu adalah sistem AI pembuat formulir/kuis otomatis. 
        Tugasmu adalah menganalisis teks hasil ekstraksi PDF berikut dan mengubahnya menjadi struktur formulir sesuai skema JSON yang diminta.
        
        Konteks Teks input:
        - Teks ini diekstrak dengan metode 'mergePage', sehingga mungkin ada nomor halaman yang menyelip atau potongan teks yang kurang rapi. Bersihkan bagian tersebut secara cerdas.
        
        Aturan Pengisian Data:
        1. Jika teks berupa kuis/ujian, set 'settings.isQuiz' menjadi true. Jika hanya formulir biasa, set false.
        2. Hitung totalScore secara kumulatif dari seluruh 'totalScore' pertanyaan.
        3. Jika jenis soal tidak disebutkan eksplisit, analisis dari konteksnya: jika ada pilihan ganda pilih 'radio' atau 'checkbox', jika isian pilih 'text'.
        
        Aturan Pembuatan ID (Format khusus):
        - Untuk 'id' di dalam 'questions', buat imitasi format 'q' + timestamp milidetik (13 digit angka). Contoh: "q1719065382123", "q1719065382124", dst.
        - Untuk 'id' di dalam 'options', buat imitasi format 'o' + timestamp milidetik (13 digit angka). Contoh: "o1719065382501", "o1719065382502", dst.
        - Cukup buat angka imitasinya saja (berurutan atau acak), yang penting polanya sama, unik untuk tiap elemen, dan hemat token.
        
        Berikut adalah teks mentah hasil ekstraksi PDF:
        ---
        ${text}
        ---`,
            },
          ],
        },
      ],
    });

    // 4. Susun struktur JSON
    const responseJson = {
      status: "success",
      meta: {
        originalName: file.name,
        sizeInBytes: file.size,
        totalPages: totalPages,
        processedAt: new Date().toISOString(),
      },
      content: response,
    };

    // 5. Kirim langsung kembali sebagai JSON response
    return NextResponse.json(responseJson);
  } catch (error) {
    console.error("Error memproses PDF di Next.js:", error);
    return NextResponse.json(
      { error: "Gagal memproses file PDF." },
      { status: 500 },
    );
  }
}
